<template><div class="void-dash-page"><div class="void-dash-header"><div><span class="void-dash-eyebrow">XINGJIAN / ORDERS</span><h1>兑换订单</h1><p class="void-dash-desc">查看积分兑换和处理实物发货</p></div></div><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>订单</th><th>用户</th><th>商品</th><th>积分</th><th>收货信息</th><th>状态</th><th>操作</th></tr></thead><tbody><tr v-for="item in items" :key="item.id"><td><strong>{{ item.orderNo }}</strong><small>{{ new Date(item.createdAt).toLocaleString('zh-CN') }}</small></td><td>{{ item.username }}</td><td>{{ item.productName }} × {{ item.quantity }}</td><td class="highlight">{{ item.pointsAmount }}</td><td>{{ item.receiverName }} {{ item.receiverPhone }}<small>{{ item.receiverAddress }}</small></td><td>{{ statusText[item.status] }}</td><td><button v-if="item.status==='paid'" class="admin-link" @click="ship(item)">标记发货</button><span v-else>-</span></td></tr></tbody></table></div></div></template>
<script setup lang="ts">definePageMeta({layout:'dashboard',middleware:'auth'});const items=ref<any[]>([]);const statusText:any={paid:'待发货',shipped:'已发货',completed:'已完成',cancelled:'已取消'};async function load(){items.value=(await $fetch<any>('/api/admin/orders')).data}async function ship(item:any){try{await $fetch(`/api/admin/orders/${item.id}/ship`,{method:'POST'});ElMessage.success('已标记发货');await load()}catch(e:any){ElMessage.error(e?.data?.message||'操作失败')}}await load()</script><style scoped lang="scss">@use '@/styles/xingjian-admin.scss' as *;</style>
